// Assemble the Anthropic request from the two prior fetches.
const today = $now.toFormat('yyyy-LL-dd');
const events = $('Get Upcoming Events').all().map(i => i.json);
const templates = $('Get Template Library').all().map(i => i.json);

const system = [
'You are the daily campaign send decider for a ticket-sales team. Each day you decide, per upcoming event, whether it deserves an email/SMS blast and which historical template to reuse. Follow these rules exactly:',
'',
'ELIGIBILITY (send only if ALL true): event_date is in the future; the event is NOT already full (filled_pct is null or < 90); a template in the library plausibly matches the event\'s market (bridge team_name -> city/metro -> the template list_name, which is a metro/region like "Cleveland", "Yankees New York City", "Georgia", "Washington DC & DMV"). If no template matches the market, decision = skip with reason "no list".',
'PRIORITISATION: lower filled_pct = higher urgency (0% is most urgent); null fill = medium.',
'TEMPLATE CHOICE: among templates matching the market, pick the best historical performer (highest open_rate, tie-break clickthru_rate; ignore rows with 0 sent_emails). Return its exact name.',
'SUPPRESSION: never recommend sending on or after the event_date.',
'',
'Return one decision per event. channel is "email" for now (SMS lists not ready). template_name is the chosen template name, or null when skipping. Keep reason to one short sentence.'
].join('\n');

const user = 'TODAY: ' + today + '\n\nUPCOMING EVENTS:\n' + JSON.stringify(events) + '\n\nTEMPLATE LIBRARY (historical blasts, list_name = market):\n' + JSON.stringify(templates);

const schema = {
  type: 'object',
  properties: {
    decisions: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          event_id: { type: 'string' },
          team: { type: 'string' },
          decision: { type: 'string', enum: ['send', 'skip'] },
          channel: { type: 'string', enum: ['email', 'sms', 'none'] },
          template_name: { type: ['string', 'null'] },
          reason: { type: 'string' }
        },
        required: ['event_id', 'team', 'decision', 'channel', 'template_name', 'reason'],
        additionalProperties: false
      }
    }
  },
  required: ['decisions'],
  additionalProperties: false
};

const body = {
  model: 'claude-opus-4-8',
  max_tokens: 8000,
  thinking: { type: 'adaptive' },
  system,
  messages: [{ role: 'user', content: user }],
  output_config: { format: { type: 'json_schema', schema } }
};

return [{ json: { body, run_date: today, event_count: events.length } }];

// Parse the structured JSON out of the Claude response into one item per decision.
const res = $json;
let text = '';
for (const b of (res.content || [])) { if (b.type === 'text' && b.text) { text = b.text; break; } }
if (!text) { throw new Error('No text block in Claude response: ' + JSON.stringify(res).slice(0, 500)); }
const parsed = JSON.parse(text);
const runDate = $('Build AI Request').first().json.run_date;
return (parsed.decisions || []).map(d => ({ json: { ...d, run_date: runDate } }));
